import { useState, useEffect } from "react";

export default function ViewByRole() {
  const [apps, setApps] = useState([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("applications")) || [];
    setApps(stored);
  }, []);

  const updateStatus = (id, status) => {
    const updated = apps.map(app =>
      app.id === id ? { ...app, status } : app
    );

    setApps(updated);
    localStorage.setItem("applications", JSON.stringify(updated));

    alert(`Application ${status}`);
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Job Applications (Admin)</h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {apps.length === 0 ? (
            <tr>
              <td colSpan="6">No Applications Found</td>
            </tr>
          ) : (
            apps.map((a, index) => (
              <tr key={a.id}>
                <td>{index + 1}</td>

                <td>
                  {(JSON.parse(localStorage.getItem("employees")) || [])
                    .find(e => e.email === a.email)?.name || "Unknown"}
                </td>

                <td>{a.email}</td>
                <td>{a.jobTitle}</td>

                <td>
                  <span
                    style={{
                      padding: "6px 12px",
                      borderRadius: "6px",
                      fontWeight: "600",
                      color: "white",
                      background:
                        a.status === "Approved"
                          ? "green"
                          : a.status === "Rejected"
                          ? "red"
                          : "#64748b",
                    }}
                  >
                    {a.status}
                  </span>
                </td>

                <td style={{ display: "flex", gap: "10px" }}>
                  <button
                    style={{
                      background: "green",
                      color: "white",
                      padding: "6px 12px",
                      borderRadius: "6px",
                      border: "none",
                    }}
                    onClick={() => updateStatus(a.id, "Approved")}
                  >
                    Approve
                  </button>

                  <button
                    style={{
                      background: "red",
                      color: "white",
                      padding: "6px 12px",
                      borderRadius: "6px",
                      border: "none",
                    }}
                    onClick={() => updateStatus(a.id, "Rejected")}
                  >
                    Reject
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}
